using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;

namespace ConstExpr.Benchmarks.MathTests;

/// <summary>
/// Compares Math.Acosh against FastAcosh variants generated by AcoshFunctionOptimizer.
///
/// BUG FOUND in the current optimizer:
///   The near-1 polynomial branch (x ∈ [1, 1.5]) computes
///     sqrt(2t) × (1 + t/12 − 3t²/160)        ← current (WRONG signs)
///   but the correct Taylor expansion of acosh(1+t)/sqrt(2t) is
///     sqrt(2t) × (1 − t/12 + 3t²/160 − …)    ← all odd-power signs inverted
///   At t = 0.4 (x = 1.4): current error ≈ 5.4e-2 rad vs expected ~6e-4 rad.
///
/// Variants:
///   FastAcosh         – current optimizer output (buggy near-1 branch)
///   FastAcosh_Fixed   – corrected polynomial signs (correct result)
///   FastAcosh_Simple  – branchless: log(x + sqrt(FMA(x,x,−1))) for all x
///                       FMA makes x²−1 numerically stable near x=1, so the
///                       polynomial special-case is unnecessary with FMA.
///
/// Test data: 50 % near-1 [1, 1.5] + 50 % general [1.5, 100] to exercise both branches.
///
/// Run command:
///   dotnet run -c Release --project ConstExpr.Benchmarks/ConstExpr.Benchmarks.csproj --filter '*AcoshBenchmark*'
/// </summary>
[MemoryDiagnoser]
[GroupBenchmarksBy(BenchmarkLogicalGroupRule.ByCategory)]
[CategoriesColumn]
public class AcoshBenchmark
{
	private const int N = 1_024;
	private float[] _floatData = null!;
	private double[] _doubleData = null!;

	[GlobalSetup]
	public void Setup()
	{
		var rng = new Random(42);
		_floatData = new float[N];
		_doubleData = new double[N];

		for (var i = 0; i < N; i++)
		{
			// 50 % near-1 [1, 1.5] — exercises the polynomial branch
			// 50 % general [1.5, 100] — exercises the log-based formula
			var v = rng.NextDouble() < 0.5
				? 1.0 + rng.NextDouble() * 0.5
				: 1.5 + rng.NextDouble() * 98.5;
			_floatData[i] = (float) v;
			_doubleData[i] = v;
		}
	}

	// ── float ──────────────────────────────────────────────────────────────

	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float DotNetAcosh_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += MathF.Acosh(v);
		return sum;
	}

	/// <summary>Current optimizer output — near-1 polynomial has inverted signs.</summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAcosh_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += CurrentAcoshFloat(v);
		return sum;
	}

	/// <summary>Corrected polynomial signs — accurate near-1 approximation without log.</summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAcosh_Float_Fixed()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += FixedAcoshFloat(v);
		return sum;
	}

	/// <summary>
	/// Branchless: log(x + sqrt(FMA(x,x,−1))) for all x.
	/// FMA computes x²−1 in one rounding — no catastrophic cancellation near x=1 —
	/// so the polynomial special-case is not needed for numerical accuracy.
	/// Removes both inner branches; always calls Single.Log once.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAcosh_Float_Simple()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += SimpleAcoshFloat(v);
		return sum;
	}

	// ── double ─────────────────────────────────────────────────────────────

	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double DotNetAcosh_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += Math.Acosh(v);
		return sum;
	}

	/// <summary>Current optimizer output — near-1 polynomial has inverted signs.</summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAcosh_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += CurrentAcoshDouble(v);
		return sum;
	}

	/// <summary>Corrected polynomial signs — accurate near-1 approximation without log.</summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAcosh_Double_Fixed()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += FixedAcoshDouble(v);
		return sum;
	}

	/// <summary>Branchless: log(x + sqrt(FMA(x,x,−1))) — see float variant for rationale.</summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAcosh_Double_Simple()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += SimpleAcoshDouble(v);
		return sum;
	}

	// ── implementations ────────────────────────────────────────────────────

	// Current optimizer output (copied verbatim)
	private static float CurrentAcoshFloat(float x)
	{
		if (x < 1.0f) x = 1.0f;
		if (x > 1e7f) return Single.Log(2.0f * x);

		if (x < 1.5f)
		{
			var t = x - 1.0f;
			var sqrt2t = Single.Sqrt(2.0f * t);
			var correction = Single.FusedMultiplyAdd(t, Single.FusedMultiplyAdd(t, -0.01875f, 0.0833333f), 1.0f);
			return sqrt2t * correction;
		}
		return Single.Log(x + Single.Sqrt(Single.FusedMultiplyAdd(x, x, -1.0f)));
	}

	private static double CurrentAcoshDouble(double x)
	{
		if (x < 1.0) x = 1.0;
		if (x > 1e15) return Double.Log(2.0 * x);

		if (x < 1.5)
		{
			var t = x - 1.0;
			var sqrt2t = Double.Sqrt(2.0 * t);
			var correction = Double.FusedMultiplyAdd(t, Double.FusedMultiplyAdd(t, Double.FusedMultiplyAdd(t, -0.005580357, 0.01875), -0.083333333333), -1.0);
			return sqrt2t * -correction;
		}
		return Double.Log(x + Double.Sqrt(Double.FusedMultiplyAdd(x, x, -1.0)));
	}

	// Fixed: polynomial signs corrected to match Taylor series 1 − t/12 + 3t²/160 − 5t³/896 + …
	private static float FixedAcoshFloat(float x)
	{
		if (x < 1.0f) x = 1.0f;
		if (x > 1e7f) return Single.Log(2.0f * x);

		if (x < 1.5f)
		{
			var t = x - 1.0f;
			var sqrt2t = Single.Sqrt(2.0f * t);
			// Horner: 1 + t * (−1/12 + t * 3/160) = 1 − t/12 + 3t²/160
			var correction = Single.FusedMultiplyAdd(t, Single.FusedMultiplyAdd(t, 0.01875f, -0.0833333f), 1.0f);
			return sqrt2t * correction;
		}
		return Single.Log(x + Single.Sqrt(Single.FusedMultiplyAdd(x, x, -1.0f)));
	}

	private static double FixedAcoshDouble(double x)
	{
		if (x < 1.0) x = 1.0;
		if (x > 1e15) return Double.Log(2.0 * x);

		if (x < 1.5)
		{
			var t = x - 1.0;
			var sqrt2t = Double.Sqrt(2.0 * t);
			// Horner: 1 + t*(−1/12 + t*(3/160 + t*(−5/896)))
			// = FMA(t, FMA(t, FMA(t, −5/896, 3/160), −1/12), 1.0)
			var correction = Double.FusedMultiplyAdd(t, Double.FusedMultiplyAdd(t, Double.FusedMultiplyAdd(t, -0.005580357, 0.01875), -0.083333333333), 1.0);
			return sqrt2t * correction; // no negation — last constant is now +1.0
		}
		return Double.Log(x + Double.Sqrt(Double.FusedMultiplyAdd(x, x, -1.0)));
	}

	// Simple: branchless formula, FMA handles near-1 precision automatically
	private static float SimpleAcoshFloat(float x)
	{
		if (x < 1.0f) x = 1.0f;
		// FMA(x,x,−1) = x²−1 in one rounding: no cancellation even for x near 1.
		// Overflow risk only for x > sqrt(Single.MaxValue/2) ≈ 1.3e19 — safe for [1, 100].
		return Single.Log(x + Single.Sqrt(Single.FusedMultiplyAdd(x, x, -1.0f)));
	}

	private static double SimpleAcoshDouble(double x)
	{
		if (x < 1.0) x = 1.0;
		return Double.Log(x + Double.Sqrt(Double.FusedMultiplyAdd(x, x, -1.0)));
	}
}